function processMessage(messages, api) {
  // Custom random generator to bypass sandbox freezing
  let seed = Math.random() * 1000000 + Date.now();
  function getSafeRandom() {
    seed = (seed * 1664525 + 1013904223) % 4294967296;
    return seed / 4294967296;
  }

  // Find the last user message
  let lastUserMsg = null;
  let lastUserIdx = -1;
  for (let i = messages.length - 1; i >= 0; i--) {
    if (messages[i].role === 'user') {
      lastUserMsg = messages[i];
      lastUserIdx = i;
      break;
    }
  }

  if (!lastUserMsg || typeof lastUserMsg.content !== 'string') return messages;

  let userMessage = lastUserMsg.content;
  let modifiedUserMessage = userMessage;

  // Parse [[set, varname, value]] commands
  const setRegex = /\[\[\s*set\s*,\s*([a-zA-Z0-9_]+)\s*,\s*(-?\d+(?:\.\d+)?)\s*\]\]/gi;
  const setMatches = [...modifiedUserMessage.matchAll(setRegex)];

  setMatches.forEach(match => {
    const fullCommand = match[0];
    const varName = match[1];
    const value = parseFloat(match[2]);
    api.setVariable(varName, value, 'set');
    modifiedUserMessage = modifiedUserMessage.replace(fullCommand, '').trim();
  });

  // Parse [[roll NdS+/-M adv/dis, operation, varname]] commands
  const rollRegex = /\[\[\s*(?:roll\s*,?\s*)?(\d+)?d(\d+)(?:([+-])(\d+))?(?:,?\s*(adv|dis))?(?:,?\s*(plus|minus|set)\s*,\s*([a-zA-Z0-9_]+))?\s*\]\]/gi;
  const matches = [...modifiedUserMessage.matchAll(rollRegex)];

  if (matches.length > 0) {
    let rollSummary = [];
    let hasNat20 = false;
    let hasNat1 = false;

    matches.forEach(match => {
      const fullCommand = match[0];
      let numDice = parseInt(match[1]) || 1;
      let numSides = parseInt(match[2]);
      const modifierSign = match[3];
      const modifier = parseInt(match[4]) || 0;
      const advDisFlag = match[5] ? match[5].toLowerCase() : null;
      const isAdvantage = advDisFlag === 'adv';
      const isDisadvantage = advDisFlag === 'dis';
      const operation = match[6] ? match[6].toLowerCase() : null;
      const targetVar = match[7];

      // Safety checks
      if (numDice > 100) numDice = 100;
      if (numSides < 2) numSides = 2;

      const rollAttempts = (isAdvantage || isDisadvantage) ? 2 : 1;
      let allAttemptResults = [];

      for (let attempt = 0; attempt < rollAttempts; attempt++) {
        let attemptRawTotal = 0;
        let attemptCritNote = '';

        for (let i = 0; i < numDice; i++) {
          const singleRoll = Math.floor(getSafeRandom() * numSides) + 1;
          attemptRawTotal += singleRoll;

          if (numSides === 20) {
            if (singleRoll === 20) attemptCritNote += ' **[NATURAL 20! CRITICAL SUCCESS!]**';
            if (singleRoll === 1) attemptCritNote += ' **[NATURAL 1! CRITICAL FAILURE!]**';
          }
        }

        allAttemptResults.push({
          rawTotal: attemptRawTotal,
          critNote: attemptCritNote
        });
      }

      // Decide which attempt to keep
      let keptAttempt = allAttemptResults[0];
      let droppedAttempt = null;

      if (rollAttempts > 1) {
        if (isAdvantage) {
          const keepFirst = allAttemptResults[0].rawTotal >= allAttemptResults[1].rawTotal;
          keptAttempt = keepFirst ? allAttemptResults[0] : allAttemptResults[1];
          droppedAttempt = keepFirst ? allAttemptResults[1] : allAttemptResults[0];
        } else {
          const keepFirst = allAttemptResults[0].rawTotal <= allAttemptResults[1].rawTotal;
          keptAttempt = keepFirst ? allAttemptResults[0] : allAttemptResults[1];
          droppedAttempt = keepFirst ? allAttemptResults[1] : allAttemptResults[0];
        }
      }

      if (keptAttempt.critNote.includes('NATURAL 20')) hasNat20 = true;
      if (keptAttempt.critNote.includes('NATURAL 1')) hasNat1 = true;

      let finalTotal = keptAttempt.rawTotal;
      if (modifierSign === '+') finalTotal += modifier;
      if (modifierSign === '-') finalTotal -= modifier;

      let droppedTotalDisplay = '';
      if (droppedAttempt) {
        let droppedFinal = droppedAttempt.rawTotal;
        if (modifierSign === '+') droppedFinal += modifier;
        if (modifierSign === '-') droppedFinal -= modifier;
        droppedTotalDisplay = ` [Dropped: ${droppedFinal}]`;
      }

      let varNote = '';
      if (operation && targetVar) {
        api.setVariable(targetVar, finalTotal, operation);
        varNote = ` [Applied ${finalTotal} to ${targetVar}]`;
      }

      let advDisString = '';
      if (isAdvantage) advDisString = ' (Advantage)';
      if (isDisadvantage) advDisString = ' (Disadvantage)';

      const diceString = `${numDice}d${numSides}${modifierSign ? modifierSign + modifier : ''}${advDisString}`;
      const inlineText = `[Rolled ${diceString}: ${finalTotal}${droppedTotalDisplay}${keptAttempt.critNote}${varNote}]`;

      modifiedUserMessage = modifiedUserMessage.replace(fullCommand, inlineText);
      rollSummary.push(`${diceString} = ${finalTotal}${keptAttempt.critNote}`);
    });

    let systemPromptContent = `[SYSTEM OVERRIDE: The user made dice rolls inline: ${rollSummary.join(', ')}. Acknowledge these results clearly at the start of your response.`;
    if (hasNat20) systemPromptContent += ` A NATURAL 20 was rolled! Narrate an epic, overwhelming success.`;
    if (hasNat1) systemPromptContent += ` A NATURAL 1 was rolled! Narrate a catastrophic, embarrassing failure.`;
    systemPromptContent += `]`;

    api.addMessage({
      role: 'system',
      content: systemPromptContent,
      append: false
    });
  }

  // Apply message replacement if modified
  if (modifiedUserMessage !== userMessage) {
    api.replaceMessage({
      find: userMessage,
      replace: modifiedUserMessage,
      target: 'user'
    });
  }

  return messages;
}
